-- J+2 : texte "Facilitateurs de vie", lien sur "Espace Bailleur gratuit", CTA et signature gérés par le template
UPDATE campaign_templates
SET
  body_html = '<p style="margin:0 0 0.5em 0;line-height:1.5;">Bonjour {{ prenom }},</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Vous avez créé une quittance récemment sur Quittance Simple.</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Je voulais vous remercier et surtout vous souhaiter la bienvenue !</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Parce que Quittance Simple, c''est un peu comme une petite communauté :<br>celle des bailleurs qui se facilitent la vie.</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Et justement, pour vous faciliter la vie, je vous ai ouvert l''accès<br>à votre <a href="https://www.quittancesimple.fr/#loginEmail={{ email }}&mode=signup" style="color:#2563eb;text-decoration:none;">Espace Bailleur gratuit</a>.</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Dedans, vous trouverez ce que j''appelle des « facilitateurs de vie ».</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Le premier ? Automatiser vos quittances sans refaire les mêmes<br>manipulations tous les mois :</p><ul style="margin:0.2em 0 0.8em 1.2em;padding-left:1em;line-height:1.5;"><li style="margin-bottom:0.35em;">Vos informations et celles de votre locataire sont déjà remplies</li><li style="margin-bottom:0.35em;">Vos quittances peuvent s''envoyer 100% automatiquement</li><li style="margin-bottom:0.1em;">Ou en un seul clic si vous préférez garder le contrôle</li></ul><p style="margin:0 0 0.5em 0;line-height:1.5;">Bref, l''idée est simple : ne plus perdre de temps avec Word, Excel,<br>les copier-coller, les envois email, les exports PDF, les archives...</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Et il y a d''autres facilitateurs dans votre Espace.<br>À vous de les découvrir — c''est gratuit !</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Petite question (je suis curieux) : combien de locataires gérez-vous<br>aujourd''hui ? Vous pouvez simplement répondre à cet email.</p><p style="margin:0 0 0.5em 0;line-height:1.5;">Merci, et encore bienvenue !</p>',
  cta_text = 'Découvrir mon espace gratuit'
WHERE campaign_key = 'j2';
